import React, { useState } from 'react';

function App() {
  const [desc, setDesc] = useState('');
  const send = () => {
    fetch('http://localhost:8000/api/orders', {
      method: 'POST',
      body: JSON.stringify({ description: desc, total_amount: 1000 })
    }).then(() => alert('Заказ отправлен!'));
  };
  return (
    <div style={{padding: '20px'}}>
      <h1>Заказ зерна Etika</h1>
      <input onChange={e => setDesc(e.target.value)} placeholder="Описание..." />
      <button onClick={send}>Отправить</button>
    </div>
  );
}
export default App;
